// Sadə xəritələnmiş tip
interface User {
  name: string;
  age: number;
}

type ReadonlyUser = { readonly [K in keyof User]: User[K] };

let user: ReadonlyUser = { name: 'Alice', age: 30 };
// user.name = 'Bob'; // Xəta: name readonly-dir

console.log(user); // { name: 'Alice', age: 30 }

// Generic tiplərlə xəritələnmiş tip
type MakeOptional<T> = { [K in keyof T]?: T[K] };

interface User {
  name: string;
  age: number;
}

type OptionalUser = MakeOptional<User>;

let user: OptionalUser = { name: 'Alice' }; // age opsionaldır

console.log(user); // { name: 'Alice' }

// Şərti tiplərlə xəritələnmiş tip
type FilterByType<T, U> = { [K in keyof T]: T[K] extends U ? T[K] : never };

interface User {
  name: string;
  age: number;
  active: boolean;
}

type StringOnlyUser = FilterByType<User, string>;

let user: StringOnlyUser = { name: 'Alice', age: null as never, active: null as never };

console.log(user); // { name: 'Alice', age: null, active: null }

// Daxili utility tipləri
interface User {
  name: string;
  age: number;
  active?: boolean;
}

type PartialUser = Partial<User>;
type RequiredUser = Required<User>;
type ReadonlyUser = Readonly<User>;
type PickUser = Pick<User, 'name' | 'age'>;
type OmitUser = Omit<User, 'active'>;

let partial: PartialUser = { name: 'Alice' }; // age və active opsionaldır
let required: RequiredUser = { name: 'Bob', age: 25, active: true }; // bütün xüsusiyyətlər tələb olunur
let readonly: ReadonlyUser = { name: 'Charlie', age: 30, active: false };
// readonly.name = 'Dave'; // Xəta: readonly-dir
let picked: PickUser = { name: 'Eve', age: 28 }; // yalnız name və age
let omitted: OmitUser = { name: 'Frank', age: 35 }; // active çıxarılıb

console.log(partial); // { name: 'Alice' }
console.log(required); // { name: 'Bob', age: 25, active: true }
console.log(readonly); // { name: 'Charlie', age: 30, active: false }
console.log(picked); // { name: 'Eve', age: 28 }
console.log(omitted); // { name: 'Frank', age: 35 }

// JavaScript-də oxşar kod
function updateUserJS(user) {
  return { ...user, name: 'Updated' };
}

console.log(updateUserJS({ name: 'Alice', age: 30 })); // { name: 'Updated', age: 30 }
console.log(updateUserJS({ name: 'Bob' })); // { name: 'Updated' }, lakin xəta yoxdur

// TypeScript-də təhlükəsiz kod
type PartialUser<T> = { [K in keyof T]?: T[K] };

function updateUserTS<T extends { name: string }>(user: PartialUser<T>): T {
  return { ...user, name: 'Updated' } as T;
}

let user = updateUserTS({ name: 'Alice', age: 30 });
console.log(user); // { name: 'Updated', age: 30 }
// let error = updateUserTS({ age: 25 }); // Xəta: name xüsusiyyəti yoxdur

// Təhlükəsizlik nümunəsi
type ReadonlyProps<T> = { readonly [K in keyof T]: T[K] };

interface User {
  name: string;
  age: number;
}

let user: ReadonlyProps<User> = { name: 'Alice', age: 30 };
// user.name = 'Bob'; // Xəta: name readonly-dir

console.log(user); // { name: 'Alice', age: 30 }

// Səhvə yol açan nümunə
function unsafeUpdateUser(user: any): any {
  return { ...user, name: 'Updated' };
}

console.log(unsafeUpdateUser({ name: 'Alice', age: 30 })); // { name: 'Updated', age: 30 }
console.log(unsafeUpdateUser({ age: 25 })); // { name: 'Updated', age: 25 }, lakin xəta yoxdur

// Düzgün yol
type PartialUser<T> = { [K in keyof T]?: T[K] };

function safeUpdateUser<T extends { name: string }>(user: PartialUser<T>): T {
  return { ...user, name: 'Updated' } as T;
}

console.log(safeUpdateUser({ name: 'Alice', age: 30 })); // { name: 'Updated', age: 30 }
// console.log(safeUpdateUser({ age: 25 })); // Xəta: name xüsusiyyəti yoxdur

// Real layihə ssenarisi
type ApiResponse<T> = { [K in keyof T]: T[K] extends string ? string : number };

interface UserResponse {
  name: string;
  age: number;
}

let response: ApiResponse<UserResponse> = { name: 'Alice', age: 30 };

console.log(response); // { name: 'Alice', age: 30 }
