// Built-in utility types
interface User {
  name: string;
  age: number;
  active?: boolean;
}

type PartialUser = Partial<User>;
type RequiredUser = Required<User>;
type ReadonlyUser = Readonly<User>;
type PickUser = Pick<User, 'name' | 'age'>;
type OmitUser = Omit<User, 'active'>;

let partial: PartialUser = { name: 'Alice' }; // age and active are optional
let required: RequiredUser = { name: 'Bob', age: 25, active: true }; // all properties are required
let readonly: ReadonlyUser = { name: 'Charlie', age: 30, active: false };
// readonly.name = 'Dave'; // Error: name is readonly
let picked: PickUser = { name: 'Eve', age: 28 }; // only name and age
